import sys

n = int(sys.stdin.readline())
k1 = int(sys.stdin.readline())
cards1 = list(map(int, sys.stdin.readline().split()))
k2 = int(sys.stdin.readline())
cards2 = list(map(int, sys.stdin.readline().split()))

def fight(cards1, cards2, count):
    if len(cards1) == 0:
        return (count, 2)
    elif len(cards2) == 0:
        return (count, 1)
    else:
        if cards1[-1] > cards2[-1]:
            cards1.append(cards2.pop())
            cards1.append(cards1.pop())
        else:
            cards2.append(cards1.pop())
            cards2.append(cards2.pop())
        return fight(cards1, cards2, count + 1)

print(*fight(cards1, cards2, 0))
